-- TOC entry 367 (class 1255 OID 16391)
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: -
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


--
-- TOC entry 463 (class 1255 OID 17903)
-- Name: compute_parts_order_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_parts_order_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  new.order_status := case
    when new.received_quantity >= new.ordered_quantity then 'Received'
    when new.confirmation_qty > 0 then 'Confirmed'
    when new.invoice_qty > 0 then 'Invoiced'
    when new.challan_qty > 0 then 'In-Transit'
    when new.order_date is not null then 'Ordered'
    else null
  end;
  return new;
end;
$$;


