INSERT INTO supabase_migrations.schema_migrations VALUES ('20260420020000', '{"-- Rebuild job_card_closed_data with strict final schema.
-- WARNING: This drops existing data from job_card_closed_data.

drop trigger if exists trg_job_card_closed_data_updated_at on job_card_closed_data","drop table if exists job_card_closed_data","create table job_card_closed_data (
  -- System columns
  id bigint primary key generated always as identity,
  branch text not null check (branch in (''Ajmer Road'', ''Sitapura PV'', ''Sitapura EV'')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),

  -- Required business columns
  job_card_number text,
  sr_type text,
  chassis_number text,
  final_labour_amount numeric,
  final_spares_amount numeric,
  total_invoice_amount numeric,
  parent_product_line text,
  product_line text,
  created_date_time timestamptz,
  closed_date_time timestamptz,
  first_name text,
  last_name text,
  sr_assigned_to text,
  vehicle_registration_number text,
  vehicle_sale_date date,
  account_phone_number text,

  -- Upsert dedupe key
  unique (job_card_number, branch)
)","create trigger trg_job_card_closed_data_updated_at
  before update on job_card_closed_data
  for each row execute function set_updated_at()","insert into import_metadata (table_name, last_updated_at)
values (''job_card_closed_data'', null)
on conflict (table_name) do nothing"}', 'reshape_job_card_closed_data');
INSERT INTO supabase_migrations.schema_migrations VALUES ('20260420120000', '{"-- Employee master data and import mapping support

create table if not exists employee_master (
  id bigint primary key generated always as identity,
  employee_code text not null unique,
  employee_name text not null,
  location text,
  department text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","create index if not exists idx_employee_master_name_normalized
  on employee_master (lower(trim(employee_name)))","alter table service_vas_jc_data
  add column if not exists employee_code text","alter table job_card_closed_data
  add column if not exists employee_code text","create index if not exists idx_service_vas_jc_data_employee_code
  on service_vas_jc_data (employee_code)","create index if not exists idx_job_card_closed_data_employee_code
  on job_card_closed_data (employee_code)","alter table service_vas_jc_data
  drop constraint if exists fk_service_vas_employee_code","alter table service_vas_jc_data
  add constraint fk_service_vas_employee_code
  foreign key (employee_code)
  references employee_master (employee_code)
  on update cascade
  on delete set null","alter table job_card_closed_data
  drop constraint if exists fk_jc_closed_employee_code","alter table job_card_closed_data
  add constraint fk_jc_closed_employee_code
  foreign key (employee_code)
  references employee_master (employee_code)
  on update cascade
  on delete set null","create table if not exists import_employee_mapping_issues (
  id bigint primary key generated always as identity,
  source_table text not null check (source_table in (''service_vas_jc_data'', ''job_card_closed_data'')),
  branch text not null check (branch in (''Ajmer Road'', ''Sitapura PV'', ''Sitapura EV'')),
  row_number integer,
  job_card_number text,
  sr_assigned_to text,
  resolved_employee_code text,
  reason text not null,
  status text not null default ''open'' check (status in (''open'', ''resolved'')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","create index if not exists idx_mapping_issues_status_created
  on import_employee_mapping_issues (status, created_at desc)","create index if not exists idx_mapping_issues_source_branch
  on import_employee_mapping_issues (source_table, branch)","alter table import_employee_mapping_issues
  drop constraint if exists fk_mapping_issue_employee_code","alter table import_employee_mapping_issues
  add constraint fk_mapping_issue_employee_code
  foreign key (resolved_employee_code)
  references employee_master (employee_code)
  on update cascade
  on delete set null","create trigger trg_employee_master_updated_at
  before update on employee_master
  for each row execute function set_updated_at()","create trigger trg_import_employee_mapping_issues_updated_at
  before update on import_employee_mapping_issues
  for each row execute function set_updated_at()"}', 'add_employee_master_and_mapping');
INSERT INTO supabase_migrations.schema_migrations VALUES ('20260420130000', '{begin,"-- 1) job_card_closed_data
alter table if exists public.job_card_closed_data
  drop constraint if exists job_card_closed_data_branch_check","update public.job_card_closed_data
set branch = case branch
  when ''AJ'' then ''Ajmer Road''
  when ''JG PV'' then ''Sitapura PV''
  when ''JG EV'' then ''Sitapura EV''
  else branch
end
where branch in (''AJ'', ''JG PV'', ''JG EV'')","alter table public.job_card_closed_data
  add constraint job_card_closed_data_branch_check
  check (branch in (''Ajmer Road'', ''Sitapura PV'', ''Sitapura EV''))","-- 2) service_invoice_data
alter table if exists public.service_invoice_data
  drop constraint if exists service_invoice_data_branch_check","update public.service_invoice_data
set branch = case branch
  when ''AJ'' then ''Ajmer Road''
  when ''JG PV'' then ''Sitapura PV''
  when ''JG EV'' then ''Sitapura EV''
  else branch
end
where branch in (''AJ'', ''JG PV'', ''JG EV'')","alter table public.service_invoice_data
  add constraint service_invoice_data_branch_check
  check (branch in (''Ajmer Road'', ''Sitapura PV'', ''Sitapura EV''))","-- 3) service_vas_jc_data
alter table if exists public.service_vas_jc_data
  drop constraint if exists service_vas_jc_data_branch_check","update public.service_vas_jc_data
set branch = case branch
  when ''AJ'' then ''Ajmer Road''
  when ''JG PV'' then ''Sitapura PV''
  when ''JG EV'' then ''Sitapura EV''
  else branch
end
where branch in (''AJ'', ''JG PV'', ''JG EV'')","alter table public.service_vas_jc_data
  add constraint service_vas_jc_data_branch_check
  check (branch in (''Ajmer Road'', ''Sitapura PV'', ''Sitapura EV''))",commit}', 'update_branch_values_in_three_tables');
INSERT INTO supabase_migrations.schema_migrations VALUES ('20260420140000', '{begin,"-- Remove hardcoded branch CHECK constraints to allow dynamic locations from employee_master

-- 1) job_card_closed_data
alter table if exists public.job_card_closed_data
  drop constraint if exists job_card_closed_data_branch_check","-- 2) service_invoice_data
alter table if exists public.service_invoice_data
  drop constraint if exists service_invoice_data_branch_check","-- 3) service_vas_jc_data
alter table if exists public.service_vas_jc_data
  drop constraint if exists service_vas_jc_data_branch_check","-- 4) import_employee_mapping_issues
alter table if exists public.import_employee_mapping_issues
  drop constraint if exists import_employee_mapping_issues_branch_check",commit}', 'fix_mapping_issues_branch_constraint');
INSERT INTO supabase_migrations.schema_migrations VALUES ('20260511000000', '{begin,"-- Shared trigger function for updated_at maintenance.
create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$","-- Employee master data.
create table if not exists public.employee_master (
  id bigint primary key generated always as identity,
  employee_code text not null unique,
  employee_name text not null,
  location text,
  department text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","create index if not exists idx_employee_master_name_normalized
  on public.employee_master (lower(trim(employee_name)))","-- Job Card Closed (final schema).
create table if not exists public.job_card_closed_data (
  id bigint primary key generated always as identity,
  branch text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  job_card_number text,
  sr_type text,
  chassis_number text,
  final_labour_amount numeric,
  final_spares_amount numeric,
  total_invoice_amount numeric,
  parent_product_line text,
  product_line text,
  created_date_time timestamptz,
  closed_date_time timestamptz,
  first_name text,
  last_name text,
  sr_assigned_to text,
  vehicle_registration_number text,
  vehicle_sale_date date,
  account_phone_number text,
  employee_code text,
  unique (job_card_number, branch),
  constraint fk_jc_closed_employee_code
    foreign key (employee_code)
    references public.employee_master (employee_code)
    on update cascade
    on delete set null
)","create index if not exists idx_job_card_closed_data_employee_code
  on public.job_card_closed_data (employee_code)","-- Service Invoice (final schema).
create table if not exists public.service_invoice_data (
  id bigint primary key generated always as identity,
  invoice_number text,
  invoice_date date,
  bill_to_first_name text,
  bill_to_last_name text,
  final_labour_invoice_amount numeric,
  final_spares_invoice_amount numeric,
  final_consolidated_invoice_amount numeric,
  order_number text,
  sr_number text,
  chassis_number text,
  vrn text,
  branch text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- Service VAS JC (final schema + employee mapping support).
create table if not exists public.service_vas_jc_data (
  id bigint primary key generated always as identity,
  branch text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  job_card_number text,
  vrn text,
  complaint_code text,
  job_code text,
  job_description text,
  job_status text,
  chassis_number text,
  model text,
  product_line text,
  billing_type text,
  sr_assigned_to text,
  rate_type text,
  sr_type text,
  performed_by text,
  sr_number text,
  net_price numeric,
  job_value numeric,
  discount numeric,
  billing_hours numeric,
  jc_closed_date_time timestamptz,
  employee_code text,
  constraint fk_service_vas_employee_code
    foreign key (employee_code)
    references public.employee_master (employee_code)
    on update cascade
    on delete set null
)","create index if not exists idx_service_vas_jc_data_employee_code
  on public.service_vas_jc_data (employee_code)","-- Service JC Parts.
create table if not exists public.service_jc_parts_data (
  id bigint primary key generated always as identity,
  jc_number text,
  service_record text,
  branch text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- Import metadata table.
create table if not exists public.import_metadata (
  id bigint primary key generated always as identity,
  table_name text not null unique,
  last_updated_at timestamptz
)","insert into public.import_metadata (table_name, last_updated_at)
values
  (''job_card_closed_data'', null),
  (''service_invoice_data'', null),
  (''service_vas_jc_data'', null),
  (''service_jc_parts_data'', null)
on conflict (table_name) do nothing","-- Employee mapping issues table.
create table if not exists public.import_employee_mapping_issues (
  id bigint primary key generated always as identity,
  source_table text not null check (source_table in (''service_vas_jc_data'', ''job_card_closed_data'')),
  branch text not null,
  row_number integer,
  job_card_number text,
  sr_assigned_to text,
  resolved_employee_code text,
  reason text not null,
  status text not null default ''open'' check (status in (''open'', ''resolved'')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint fk_mapping_issue_employee_code
    foreign key (resolved_employee_code)
    references public.employee_master (employee_code)
    on update cascade
    on delete set null
)","create index if not exists idx_mapping_issues_status_created
  on public.import_employee_mapping_issues (status, created_at desc)","create index if not exists idx_mapping_issues_source_branch
  on public.import_employee_mapping_issues (source_table, branch)","-- Updated_at triggers.
drop trigger if exists trg_employee_master_updated_at on public.employee_master","create trigger trg_employee_master_updated_at
  before update on public.employee_master
  for each row execute function public.set_updated_at()","drop trigger if exists trg_job_card_closed_data_updated_at on public.job_card_closed_data","create trigger trg_job_card_closed_data_updated_at
  before update on public.job_card_closed_data
  for each row execute function public.set_updated_at()","drop trigger if exists trg_service_invoice_data_updated_at on public.service_invoice_data","create trigger trg_service_invoice_data_updated_at
  before update on public.service_invoice_data
  for each row execute function public.set_updated_at()","drop trigger if exists trg_service_vas_jc_data_updated_at on public.service_vas_jc_data","create trigger trg_service_vas_jc_data_updated_at
  before update on public.service_vas_jc_data
  for each row execute function public.set_updated_at()","drop trigger if exists trg_service_jc_parts_data_updated_at on public.service_jc_parts_data","create trigger trg_service_jc_parts_data_updated_at
  before update on public.service_jc_parts_data
  for each row execute function public.set_updated_at()","drop trigger if exists trg_import_employee_mapping_issues_updated_at on public.import_employee_mapping_issues","create trigger trg_import_employee_mapping_issues_updated_at
  before update on public.import_employee_mapping_issues
  for each row execute function public.set_updated_at()",commit}', 'baseline_full_setup');
INSERT INTO supabase_migrations.schema_migrations VALUES ('20260511103000', '{begin,"-- Parts consumption transactions (history).
create table if not exists public.service_parts_consumption_data (
  id bigint primary key generated always as identity,
  part_number text not null,
  part_description text,
  transaction_date date,
  quantity_consumed numeric not null default 0,
  unit_cost numeric,
  total_cost numeric,
  source_reference text,
  source_row_hash text not null,
  branch text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- Parts order and in-transit data (history).
create table if not exists public.service_parts_order_data (
  id bigint primary key generated always as identity,
  part_number text not null,
  part_description text,
  order_date date,
  expected_date date,
  ordered_quantity numeric not null default 0,
  received_quantity numeric not null default 0,
  backorder_quantity numeric not null default 0,
  status text,
  source_document_id text,
  source_row_hash text not null,
  branch text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- On-hand inventory snapshots.
create table if not exists public.service_parts_stock_snapshot_data (
  id bigint primary key generated always as identity,
  part_number text not null,
  part_description text,
  snapshot_date date not null,
  on_hand_quantity numeric not null default 0,
  weighted_cost numeric,
  inventory_value numeric,
  source_row_hash text not null,
  branch text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- Optional canonical part metadata (global part number key).
create table if not exists public.part_master (
  part_number text primary key,
  part_description text,
  uom text,
  category text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
)","-- Replace legacy import metadata entry for parts sheet with three new sheets.
delete from public.import_metadata
where table_name = ''service_jc_parts_data''","insert into public.import_metadata (table_name, last_updated_at)
values
  (''service_parts_consumption_data'', null),
  (''service_parts_order_data'', null),
  (''service_parts_stock_snapshot_data'', null)
on conflict (table_name) do nothing","-- Uniqueness for idempotent re-imports.
create unique index if not exists uq_parts_consumption_conflict
  on public.service_parts_consumption_data (part_number, branch, transaction_date, source_row_hash)","create unique index if not exists uq_parts_order_conflict
  on public.service_parts_order_data (part_number, branch, order_date, source_row_hash)","create unique index if not exists uq_parts_stock_conflict
  on public.service_parts_stock_snapshot_data (part_number, branch, snapshot_date, source_row_hash)","-- Reporting and filtering indexes.
create index if not exists idx_parts_consumption_part
  on public.service_parts_consumption_data (part_number)","create index if not exists idx_parts_consumption_branch_date
  on public.service_parts_consumption_data (branch, transaction_date)","create index if not exists idx_parts_order_part
  on public.service_parts_order_data (part_number)","create index if not exists idx_parts_order_branch_date
  on public.service_parts_order_data (branch, order_date)","create index if not exists idx_parts_stock_part
  on public.service_parts_stock_snapshot_data (part_number)","create index if not exists idx_parts_stock_branch_date
  on public.service_parts_stock_snapshot_data (branch, snapshot_date)","-- Keep part_master synchronized from imports.
insert into public.part_master (part_number, part_description)
select distinct part_number, nullif(part_description, '''')
from public.service_parts_consumption_data
where part_number is not null and trim(part_number) <> ''''
on conflict (part_number) do nothing","insert into public.part_master (part_number, part_description)
select distinct part_number, nullif(part_description, '''')
from public.service_parts_order_data
where part_number is not null and trim(part_number) <> ''''
on conflict (part_number) do nothing","insert into public.part_master (part_number, part_description)
select distinct part_number, nullif(part_description, '''')
from public.service_parts_stock_snapshot_data
where part_number is not null and trim(part_number) <> ''''
on conflict (part_number) do nothing","-- updated_at triggers.
