  on public.parts_alerts_config
  for insert
  to anon, authenticated
  with check (true)","drop policy if exists parts_alerts_config_update_anon on public.parts_alerts_config","create policy parts_alerts_config_update_anon
  on public.parts_alerts_config
  for update
  to anon, authenticated
  using (true)
  with check (true)","drop policy if exists parts_alerts_config_delete_anon on public.parts_alerts_config","create policy parts_alerts_config_delete_anon
  on public.parts_alerts_config
  for delete
  to anon, authenticated
  using (true)","-- Index for alert lookups
create index if not exists idx_parts_alerts_config_branch_type
