  constraint fk_parts_alerts_log_config
    foreign key (config_id)
    references public.parts_alerts_config (id)
    on delete cascade
)","-- RLS policies for alerts log
alter table public.parts_alerts_log enable row level security","drop policy if exists parts_alerts_log_select_anon on public.parts_alerts_log","create policy parts_alerts_log_select_anon
